fixed_code:
struct Foo<T>(T);

impl<T: Copy + std::ops::Add<Output = T>> Foo<T> {
    fn add(&self, other: &Self) -> Self {
        Foo(self.0 + other.0)
    }
}

fn main() {
    let a = Foo(2147483647_i32);
    let b = Foo(1);
    println!("{}", a.add(&b).0);
}

